content.css:
* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { font-family: -apple-system, "PingFang SC", "Microsoft YaHei", sans-serif; background: #faf7f2; color: #1f2937; height: 100%; }
#dash-root { padding: 16px; min-height: 100vh; }
.dash-loading { color: #6b7280; padding: 32px; text-align: center; }
.dash-header { margin-bottom: 16px; }
.dash-title { font-size: 20px; font-weight: 600; color: #1f2937; }
.dash-sub { font-size: 12px; color: #6b7280; margin-top: 4px; }
.kpi-row { display: grid; grid-template-columns: repeat(4, 1fr); gap: 12px; margin-bottom: 14px; }
.kpi-card { background: #ffffff; padding: 16px 18px; border-radius: 12px; border: 1px solid #e5e7eb; box-shadow: 0 1px 2px rgba(15,23,42,0.04); position: relative; overflow: hidden; }
.kpi-card::before { content: ''; position: absolute; top: 0; left: 0; right: 0; height: 3px; background: linear-gradient(90deg, #d97706 0%, #2563eb 100%); }
.kpi-label { font-size: 11px; color: #6b7280; margin-bottom: 8px; letter-spacing: 0.3px; }
.kpi-value { font-size: 28px; font-weight: 700; color: #111827; line-height: 1.1; font-variant-numeric: tabular-nums; }
.kpi-trend { font-size: 11px; color: #059669; margin-top: 6px; }
.kpi-trend.neutral { color: #6b7280; }
.kpi-trend.down { color: #dc2626; }
.grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.grid-3 { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.chart-card { background: #ffffff; border-radius: 12px; border: 1px solid #e5e7eb; padding: 14px 16px 10px; box-shadow: 0 1px 2px rgba(15,23,42,0.04); }
.chart-title { font-size: 13px; font-weight: 600; margin-bottom: 8px; color: #1f2937; display: flex; justify-content: space-between; align-items: center; }
.chart-title .tag { font-size: 10px; font-weight: 400; color: #6b7280; padding: 2px 6px; background: #f3f4f6; border-radius: 4px; }
.chart-body { width: 100%; height: 260px; }
.chart-body.h180 { height: 180px; }
.chart-body.h320 { height: 320px; }
table.dash-tbl { width: 100%; border-collapse: collapse; font-size: 12px; }
table.dash-tbl th { text-align: left; padding: 6px 10px; color: #6b7280; font-weight: 500; border-bottom: 1px solid #e5e7eb; font-size: 10px; letter-spacing: 0.3px; text-transform: uppercase; }
table.dash-tbl td { padding: 8px 10px; border-bottom: 1px solid #f3f4f6; color: #374151; }
table.dash-tbl tr:hover td { background: #fafaf7; }
.tag-pri { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; font-weight: 600; letter-spacing: 0.3px; }
.tag-pri.P0 { background: #fee2e2; color: #dc2626; }
.tag-pri.P1 { background: #fef3c7; color: #d97706; }
.tag-pri.P2 { background: #dbeafe; color: #2563eb; }
.tag-risk { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-risk.高风险 { background: #fee2e2; color: #dc2626; }
.tag-risk.中风险 { background: #fef3c7; color: #d97706; }
.tag-risk.正常 { background: #d1fae5; color: #059669; }
.tag-role { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 10px; }
.tag-role.金牌导购 { background: #fef3c7; color: #d97706; }
.tag-role.普通导购 { background: #e5e7eb; color: #4b5563; }
.tag-role.新人导购 { background: #ddd6fe; color: #7c3aed; }
.tag-role.店长 { background: #d1fae5; color: #059669; }

/* ========== 移动端响应式 (BI ?pageRenderType=phoneView) ========== */
@media (max-width: 768px) {
  html, body { height: auto !important; overflow-y: auto !important; }
  #dash-root { padding: 10px; overflow-y: auto; -webkit-overflow-scrolling: touch; } /* iframe-mobile-scroll */
  .dash-header { margin-bottom: 10px; }
  .dash-title { font-size: 16px; }
  .dash-sub { font-size: 11px; }
  .kpi-row, .grid-2, .grid-3 { grid-template-columns: 1fr 1fr !important; gap: 8px !important; margin-bottom: 10px !important; }
  .kpi-card { padding: 10px 12px; border-radius: 8px; }
  .kpi-label { font-size: 10px; margin-bottom: 4px; }
  .kpi-value { font-size: 18px; }
  .kpi-trend { font-size: 10px; }
  .chart-card { padding: 10px 12px 6px; border-radius: 8px; }
  .chart-title { font-size: 12px; margin-bottom: 6px; }
  .chart-title .tag { font-size: 9px; padding: 1px 4px; }
  .chart-body { height: 200px !important; }
  .chart-body.h180 { height: 160px !important; }
  .chart-body.h220 { height: 180px !important; }
  .chart-body.h320 { height: 240px !important; }
  table.dash-tbl { font-size: 11px; }
  table.dash-tbl th { font-size: 9px; padding: 4px 6px; }
  table.dash-tbl td { padding: 5px 6px; }
  .chip-toolbar { padding: 6px 8px; font-size: 10px; gap: 2px; }
  .chip { padding: 3px 8px; font-size: 10px; margin: 0; }
}
@media (max-width: 480px) {
  .kpi-row { grid-template-columns: 1fr 1fr !important; }
  .grid-2 { grid-template-columns: 1fr !important; }
  .kpi-value { font-size: 16px; }
  .chart-body { height: 180px !important; }
  .chart-body.h180 { height: 150px !important; }
  .chart-body.h320 { height: 220px !important; }
}

content.script:
/**
 * 02-会员私域驾驶舱
 * data[0]: RFM 标签 / 会员数 / 消费金额
 * data[1]: 会员等级 × RFM 标签 / 会员数
 * data[2]: 注册渠道 / 会员数 / 消费金额
 */

function fmtNum(v){if(v==null||isNaN(v))return"—";v=Number(v);if(Math.abs(v)>=1e8)return(v/1e8).toFixed(2)+" 亿";if(Math.abs(v)>=1e4)return(v/1e4).toFixed(1)+" 万";return Math.round(v).toLocaleString();}
function fmtPct(v){if(v==null||isNaN(v))return"—";return(Number(v)*100).toFixed(1)+"%";}
function getCol(view,name){if(!view)return null;for(var i=0;i<view.length;i++){if(view[i]&&view[i].name===name)return view[i];}return null;}
function sumArr(a){var s=0;if(!a)return 0;for(var i=0;i<a.length;i++){var v=Number(a[i]);if(!isNaN(v))s+=v;}return s;}

function renderChart(data, clickFunc, config){
  var root=document.getElementById('dash-root');
  if(!data||!data[0]){root.innerHTML='<div class="dash-loading">No data</div>';return;}

  // dataView 0: RFM 标签汇总
  var v0=data[0];
  var rfmLabels=(getCol(v0,"RFM标签")||{}).data||[];
  var rfmCount=(getCol(v0,"会员ID")||{}).data||[];
  var rfmGmv=(getCol(v0,"消费金额")||{}).data||[];

  // KPI 计算
  var totalMembers=sumArr(rfmCount);
  var totalGmv=sumArr(rfmGmv);
  var vipIdx=rfmLabels.indexOf("重要价值客户");
  var vipCount=vipIdx>=0?Number(rfmCount[vipIdx])||0:0;
  var vipGmv=vipIdx>=0?Number(rfmGmv[vipIdx])||0:0;
  var vipShare=totalMembers?vipCount/totalMembers:0;
  var vipGmvShare=totalGmv?vipGmv/totalGmv:0;
  // 重要类别: 重要价值 + 重要发展 + 重要保持 + 重要挽留
  var importantCount=0, importantGmv=0;
  ["重要价值客户","重要发展客户","重要保持客户","重要挽留客户"].forEach(function(lab){
    var i=rfmLabels.indexOf(lab);
    if(i>=0){importantCount+=Number(rfmCount[i])||0;importantGmv+=Number(rfmGmv[i])||0;}
  });
  var importantGmvShare=totalGmv?importantGmv/totalGmv:0;

  // dataView 2: 注册渠道
  var v2=data[2];
  var chNames=(getCol(v2,"注册渠道")||{}).data||[];
  var chCount=(getCol(v2,"会员ID")||{}).data||[];
  var chGmv=(getCol(v2,"消费金额")||{}).data||[];

  root.innerHTML=(
    '<div class="dash-header">'+
      '<div class="dash-title">👥 会员私域驾驶舱</div>'+
      '<div class="dash-sub">RFM 分层 · 80/20 故事 · '+totalMembers.toLocaleString()+' 名活跃会员</div>'+
    '</div>'+
    '<div class="kpi-row">'+
      '<div class="kpi-card"><div class="kpi-label">活跃会员总数</div><div class="kpi-value">'+fmtNum(totalMembers)+'</div><div class="kpi-trend">▲ 重要客群价值释放</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">重要价值客户占比</div><div class="kpi-value">'+fmtPct(vipShare)+'</div><div class="kpi-trend">'+fmtNum(vipCount)+' 人</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">重要价值客户消费占比</div><div class="kpi-value">'+fmtPct(vipGmvShare)+'</div><div class="kpi-trend">80/20 法则验证</div></div>'+
      '<div class="kpi-card"><div class="kpi-label">所有重要客群消费占比</div><div class="kpi-value">'+fmtPct(importantGmvShare)+'</div><div class="kpi-trend">重要客群 = 营收引擎</div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">RFM 标签分布·人数 <span class="tag">9 类标签</span></div><div id="c-rfm-cnt" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">RFM 标签·消费金额 <span class="tag">80/20 集中度</span></div><div id="c-rfm-gmv" class="chart-body"></div></div>'+
    '</div>'+
    '<div class="grid-2">'+
      '<div class="chart-card"><div class="chart-title">会员等级 × RFM 标签 <span class="tag">交叉透视</span></div><div id="c-tier-rfm" class="chart-body"></div></div>'+
      '<div class="chart-card"><div class="chart-title">注册渠道·会员数 + 人均消费 <span class="tag">渠道质量</span></div><div id="c-channel" class="chart-body"></div></div>'+
    '</div>'
  );

  function ch(id){return echarts.init(document.getElementById(id));}
  function baseOpt(){return{backgroundColor:'transparent',tooltip:{trigger:'axis',backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},extraCssText:'box-shadow:0 4px 12px rgba(15,23,42,0.08);border-radius:6px;'},grid:{left:80,right:30,top:25,bottom:40},animation:true};}

  // 调色板 (RFM 9 类)
  var RFM_COLORS={
    "重要价值客户":"#dc2626","重要发展客户":"#d97706","重要保持客户":"#f59e0b","重要挽留客户":"#ea580c",
    "一般价值客户":"#2563eb","一般发展客户":"#0891b2","一般保持客户":"#06b6d4","一般挽留客户":"#0d9488",
    "中间客群":"#6b7280"
  };
  // 排序 RFM 数据 (按消费金额降序)
  var sortIdx=rfmLabels.map(function(_,i){return i;}).sort(function(a,b){return (Number(rfmGmv[b])||0)-(Number(rfmGmv[a])||0);});
  var sLabels=sortIdx.map(function(i){return rfmLabels[i];});
  var sCount=sortIdx.map(function(i){return Number(rfmCount[i])||0;});
  var sGmv=sortIdx.map(function(i){return Number(rfmGmv[i])||0;});
  var sColors=sLabels.map(function(l){return RFM_COLORS[l]||'#94a3b8';});

  // 1. RFM 人数 (横向条形, 含人数百分比)
  ch('c-rfm-cnt').setOption(Object.assign(baseOpt(),{
    tooltip:{trigger:'item',backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},formatter:function(p){var pct=totalMembers?(p.value/totalMembers*100).toFixed(1):0;return p.name+'<br/>'+fmtNum(p.value)+' 人 ('+pct+'%)';}},
    grid:{left:90,right:60,top:10,bottom:25},
    xAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    yAxis:{type:'category',data:sLabels,axisLabel:{color:'#374151',fontSize:11},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    series:[{type:'bar',data:sCount.map(function(v,i){return {value:v,itemStyle:{color:sColors[i],borderRadius:[0,4,4,0]}};}),label:{show:true,position:'right',color:'#374151',formatter:function(p){return fmtNum(p.value);}}}]
  }));

  // 2. RFM 消费金额 (横向条形)
  ch('c-rfm-gmv').setOption(Object.assign(baseOpt(),{
    tooltip:{trigger:'item',backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},formatter:function(p){var pct=totalGmv?(p.value/totalGmv*100).toFixed(1):0;return p.name+'<br/>'+fmtNum(p.value)+' 元 ('+pct+'%)';}},
    grid:{left:90,right:60,top:10,bottom:25},
    xAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    yAxis:{type:'category',data:sLabels,axisLabel:{color:'#374151',fontSize:11},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    series:[{type:'bar',data:sGmv.map(function(v,i){return {value:v,itemStyle:{color:sColors[i],borderRadius:[0,4,4,0]}};}),label:{show:true,position:'right',color:'#374151',formatter:function(p){return fmtNum(p.value);}}}]
  }));

  // 3. 会员等级 × RFM 标签 堆叠柱
  var v1=data[1];
  var v1Tier=(getCol(v1,"会员等级")||{}).data||[];
  var v1Rfm=(getCol(v1,"RFM标签")||{}).data||[];
  var v1Cnt=(getCol(v1,"会员ID")||{}).data||[];
  // 透视: tier -> {rfmLabel: cnt}
  var matrix={};
  var tiers=["普卡","银卡","金卡","黑卡"];
  tiers.forEach(function(t){matrix[t]={};});
  for(var i=0;i<v1Tier.length;i++){
    var t=v1Tier[i],r=v1Rfm[i];
    if(!matrix[t])matrix[t]={};
    matrix[t][r]=(matrix[t][r]||0)+(Number(v1Cnt[i])||0);
  }
  var rfmCats=["重要价值客户","重要发展客户","重要保持客户","重要挽留客户","一般价值客户","一般发展客户","一般保持客户","一般挽留客户","中间客群"];
  var series=rfmCats.map(function(r){
    return {name:r,type:'bar',stack:'all',itemStyle:{color:RFM_COLORS[r]||'#94a3b8'},data:tiers.map(function(t){return matrix[t][r]||0;})};
  });
  ch('c-tier-rfm').setOption(Object.assign(baseOpt(),{
    legend:{data:rfmCats,textStyle:{color:'#6b7280',fontSize:9},top:0,type:'scroll'},
    tooltip:{trigger:'axis',axisPointer:{type:'shadow'},backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},
      formatter:function(p){var s='<b>'+p[0].axisValueLabel+'</b><br/>';p.forEach(function(x){if(x.value)s+=x.marker+x.seriesName+': '+fmtNum(x.value)+' 人<br/>';});return s;}},
    grid:{left:55,right:20,top:55,bottom:30},
    xAxis:{type:'category',data:tiers,axisLabel:{color:'#374151',fontSize:11},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    yAxis:{type:'value',axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
    series:series
  }));

  // 4. 注册渠道 双轴 (人数 + 人均消费)
  var perCapita=chNames.map(function(_,i){var c=Number(chCount[i])||0;return c?Math.round((Number(chGmv[i])||0)/c):0;});
  ch('c-channel').setOption(Object.assign(baseOpt(),{
    legend:{data:['会员数','人均消费'],textStyle:{color:'#6b7280'},top:0,right:10},
    tooltip:{trigger:'axis',backgroundColor:'#fff',borderColor:'#e5e7eb',textStyle:{color:'#1f2937'},
      formatter:function(p){var s='<b>'+p[0].axisValueLabel+'</b><br/>';p.forEach(function(x){if(x.value!=null){var unit=x.seriesName.indexOf('消费')>=0?' 元':' 人';s+=x.marker+x.seriesName+': '+fmtNum(x.value)+unit+'<br/>';}});return s;}},
    grid:{left:60,right:60,top:35,bottom:30},
    xAxis:{type:'category',data:chNames,axisLabel:{color:'#374151',fontSize:10},axisLine:{lineStyle:{color:'#e5e7eb'}}},
    yAxis:[
      {type:'value',name:'会员数',nameTextStyle:{color:'#6b7280',fontSize:10},axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}},splitLine:{lineStyle:{color:'#f3f4f6'}}},
      {type:'value',name:'人均(元)',nameTextStyle:{color:'#6b7280',fontSize:10},axisLabel:{color:'#6b7280',formatter:function(v){return fmtNum(v);}}}
    ],
    series:[
      {name:'会员数',type:'bar',itemStyle:{color:'#2563eb',borderRadius:[4,4,0,0]},data:chCount.map(function(v){return Number(v)||0;})},
      {name:'人均消费',type:'line',yAxisIndex:1,lineStyle:{width:2,color:'#d97706'},itemStyle:{color:'#d97706'},symbol:'circle',symbolSize:6,data:perCapita}
    ]
  }));
}

new GDPlugin().init(renderChart);
